import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.CxZWPeXl.js";const d=JSON.parse('{"title":"Stage Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/admin-stages.md","filePath":"en/admin-stages.md"}'),r={name:"en/admin-stages.md"};function o(n,e,l,c,u,h){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="stage-management" tabindex="-1">Stage Management <a class="header-anchor" href="#stage-management" aria-label="Permalink to &quot;Stage Management&quot;">​</a></h1><blockquote><p>Define sales practice stages, setting evaluation standards and objectives.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sales stages are the foundation of the practice sessions. Each stage represents a crucial step in the conversation; the AI will monitor and evaluate the user based on this configuration.</p><blockquote><p>Access is restricted to Administrators only.</p></blockquote><h2 id="interface-structure" tabindex="-1">Interface Structure <a class="header-anchor" href="#interface-structure" aria-label="Permalink to &quot;Interface Structure&quot;">​</a></h2><p>The management page displays a list of stages ordered numerically (typically 1 to 5):</p><ul><li><strong>Card Title</strong>: Format &quot;Stage N: {Stage Name}&quot; (supports bilingual display).</li><li><strong>Customer Status (Description)</strong>: The expected psychological state or behavior of the customer during this step.</li><li><strong>Action Buttons</strong>: Icons to Edit (pencil) or Delete (trash bin) the stage.</li></ul><hr><h2 id="stage-attributes" tabindex="-1">Stage Attributes <a class="header-anchor" href="#stage-attributes" aria-label="Permalink to &quot;Stage Attributes&quot;">​</a></h2><h3 id="stage-number" tabindex="-1">Stage Number <a class="header-anchor" href="#stage-number" aria-label="Permalink to &quot;Stage Number&quot;">​</a></h3><ul><li>Determines the sequential order. Must be a positive integer and unique. Cannot be modified after creation.</li></ul><h3 id="stage-name" tabindex="-1">Stage Name <a class="header-anchor" href="#stage-name" aria-label="Permalink to &quot;Stage Name&quot;">​</a></h3><ul><li>The official name of the sales step (e.g., 1. Ice-breaking, 2. Needs Discovery, 3. Closing). Bilingual input supported.</li></ul><h3 id="current-customer-status" tabindex="-1">Current Customer Status <a class="header-anchor" href="#current-customer-status" aria-label="Permalink to &quot;Current Customer Status&quot;">​</a></h3><ul><li>Describes the psychological state of the customer. The AI uses this as a benchmark to assess whether the agent has successfully overcome this specific psychological barrier.</li></ul><hr><h2 id="operations" tabindex="-1">Operations <a class="header-anchor" href="#operations" aria-label="Permalink to &quot;Operations&quot;">​</a></h2><ul><li><strong>Add Stage</strong>: Click the Add button to input Number, Name, and Description in the designated languages.</li><li><strong>Edit</strong>: Click the edit icon on the card (Note: Stage Number cannot be edited).</li><li><strong>Delete</strong>: Click the delete icon. Warning: Deleting a stage might impact the evaluation reports of previous practice histories.</li></ul><hr><h2 id="design-recommendations" tabindex="-1">Design Recommendations <a class="header-anchor" href="#design-recommendations" aria-label="Permalink to &quot;Design Recommendations&quot;">​</a></h2><ol><li><strong>Logical Progression</strong>: Order from easiest to hardest, following a natural sales flow.</li><li><strong>Clear Objectives</strong>: Each stage should have specific, measurable goals for the AI to score effectively.</li><li><strong>Realistic Descriptions</strong>: Customer psychological states should accurately reflect reality.</li><li><strong>Appropriate Quantity</strong>: Between 3 to 7 stages is optimal for a single practice session.</li></ol>',22)])])}const m=t(r,[["render",o]]);export{d as __pageData,m as default};
